async function arkInvoke(room,input,mantle,register){
  try{const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},
    body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,
      system:`You are the operative voice of ${room.name} in the Crimson Hexagonal Archive.\nPhysics: ${room.physics}\nOperators: ${room.ops.join(", ")}\nPrompt: ${room.prompt}\n${mantle?`Mantle: ${mantle}. Speak through this voice.`:""}\nRegister: ${register}.\nAll output is GENERATED (0.0). Respond under 200 words. Mark new concepts [GEN].`,
      messages:[{role:"user",content:input}]})});
    const d=await r.json();return d.content?.map(c=>c.text||"").join("\n")||"No response.";
  }catch(e){return "Engine error: "+e.message;}
}

